  ('disabled-c5fb3965-moex-00141', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '下列違反戶籍法之行為，何者可能遭科以罰金？', '["冒用身分而使用他人遺失之國民身分證，足生損害於他人", "故意為不實之戶籍登記申請", "無正當理由拒絕接受戶口調查", "戶內人口辦理戶籍登記時，戶長故意扣留戶口名簿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00142', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '依戶籍法規定，在兒童及少年福利機構安置教養之中華民國人民，初次申 請戶籍登記時，關於其出生地之認定，下列敘述何者錯誤？', '["以其出生地所屬之省（市）及縣（市）為出生地", "出生地不明者，以該機構所在地為出生地", "發現地不明者，以該機構所在地為出生地", "不能確定其出生地者，以首都所在地為出生地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00143', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '甲因歸化為其他國家國民而喪失我國國籍，原戶籍登記應如何處理？', '["撤銷戶籍登記", "廢止戶籍登記", "更正戶籍登記", "變更戶籍登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00144', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '關於戶口調查，下列敘述何者錯誤？', '["戶口清查日，由直轄市、縣（市）政府定之", "無正當理由拒絕接受戶口調查者，處新臺幣3千元以上9千元以下罰鍰", "戶口調查應查記戶內居住已滿或預期居住3個月以上之現住人口", "需按戶逐口辦理戶口調查時，交由村（里）鄰長、村（里）幹事、警勤 區員警及入出國管理機關人員共同辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00145', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '有關教育事務之戶籍行政事項，下列何者與戶籍法不符？', '["學校如果拒絕依法提供查證戶籍登記事項之資料，將被處以罰鍰", "人民如滿15歲，各級主管機關與戶政事務所應查記其教育程度", "各級學校每年應編造畢（結）業及新生名冊，通報中央主管機關", "因就學而搬離原鄉（鎮、市、區）3個月以上，得不為遷出登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00146', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '某甲死亡，繼承人領得除戶戶籍謄本後，發現謄本把某甲生前最後戶籍地 的地址打錯，請問應由何地戶政事務所辦理更正？', '["繼承人戶籍地戶政事務所", "某甲最後戶籍地戶政事務所", "國內任一戶政事務所", "中央政府所在地戶政事務所"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
