  ('disabled-c5fb3965-moex-00149', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '有關新生兒之出生登記，內政部透過網路傳輸方式，取得由衛生福利部國 民健康署傳輸之出生通報資料，發現母為外國籍而父不詳時，應如何處 理？', '["下傳至戶政事務所", "退回衛生福利部國民健康署", "交給外交部，通知其母所屬國", "由內政部移民署取回資料，內政部戶政司複製一份"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00150', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '戶政事務所逕行撤銷當事人虛報之遷徙登記後，發現當事人已死亡，依戶 籍法規應如何處理？', '["應將遷徙登記之撤銷公告於戶政事務所公布欄", "因當事人已喪失權利能力，故不需為任何處理", "應通知當事人的配偶或一親等之直系血親", "應將撤銷遷徙登記之事實刊登於政府公報"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
